     1→//! Core API functions for TemplateFlow
     2→//!
     3→//! This module implements the main public API functions:
     4→//! - `ls`: List files for a template with BIDS queries
     5→//! - `get`: Download and return file paths
     6→//! - `templates`: List available templates
     7→//! - `get_metadata`: Get template metadata
     8→//! - `get_citations`: Get template citations
     9→
    10→use crate::bids::{TemplateLayout, TemplateMetadata};
    11→use crate::config::CONFIG;
    12→use crate::error::{Result, TemplateFlowError};
    13→use crate::s3;
    14→use once_cell::sync::Lazy;
    15→use std::collections::HashMap;
    16→use std::path::PathBuf;
    17→use std::sync::{Arc, Mutex};
    18→
    19→/// Global template layout instance
    20→static LAYOUT: Lazy<Arc<Mutex<Option<TemplateLayout>>>> = Lazy::new(|| Arc::new(Mutex::new(None)));
    21→
    22→/// Ensure the layout is loaded
    23→fn ensure_layout() -> Result<()> {
    24→    let mut layout_guard = LAYOUT.lock().unwrap();
    25→    
    26→    if layout_guard.is_none() {
    27→        // Download skeleton if needed
    28→        let skeleton_path = CONFIG.skeleton_path();
    29→        if !skeleton_path.exists() {
    30→            s3::update_skeleton_sync()?;
    31→        }
    32→        
    33→        // Load the layout
    34→        let layout = crate::bids::load_skeleton_from_file(&skeleton_path)?;
    35→        *layout_guard = Some(layout);
    36→    }
    37→    
    38→    Ok(())
    39→}
    40→
    41→/// Get template metadata
    42→///
    43→/// Retrieves metadata for a specific brain template including name, description,
    44→/// authors, license, and references. The metadata is first checked in the skeleton
    45→/// cache, and if not found, downloaded from S3.
    46→///
    47→/// # Arguments
    48→/// * `template` - Template identifier (e.g., "MNI152Lin", "MNI152NLin2009cAsym")
    49→///
    50→/// # Returns
    51→/// * `Result<TemplateMetadata>` - The template metadata containing:
    52→///   - `name`: Template display name
    53→///   - `description`: Optional template description
    54→///   - `authors`: List of template authors
    55→///   - `license`: Optional license information
    56→///   - `references_and_links`: Related publications and resources
    57→///
    58→/// # Errors
    59→/// Returns `TemplateFlowError::TemplateNotFound` if the template doesn't exist
    60→/// or `TemplateFlowError::DownloadError` if network issues occur.
    61→///
    62→/// # Example
    63→/// ```no_run
    64→/// use templateflow::api::get_metadata;
    65→/// 
    66→/// let metadata = get_metadata("MNI152Lin").unwrap();
    67→/// println!("Template name: {}", metadata.name);
    68→/// println!("Authors: {:?}", metadata.authors);
    69→/// if let Some(license) = &metadata.license {
    70→///     println!("License: {}", license);
    71→/// }
    72→/// ```
    73→pub fn get_metadata(template: &str) -> Result<TemplateMetadata> {
    74→    ensure_layout()?;
    75→    
    76→    let layout_guard = LAYOUT.lock().unwrap();
    77→    let layout = layout_guard.as_ref().unwrap();
    78→    
    79→    // First check if metadata exists in the skeleton
    80→    if let Some(metadata) = layout.get_metadata(template) {
    81→        return Ok(metadata.clone());
    82→    }
    83→    
    84→    // If not in skeleton, try to download template_description.json
    85→    let template_dir = CONFIG.home.join(format!("tpl-{}", template));
    86→    let metadata_path = template_dir.join("template_description.json");
    87→    
    88→    // Download if not cached
    89→    if !metadata_path.exists() {
    90→        let s3_path = format!("tpl-{}/template_description.json", template);
    91→        s3::download_file_sync(&s3_path, &metadata_path, false)?;
    92→    }
    93→    
    94→    // Parse the metadata
    95→    TemplateMetadata::from_file(&metadata_path)
    96→}
    97→
    98→/// Get template citations
    99→///
   100→/// Retrieves citation information for a specific brain template. Citations can be
   101→/// returned as raw references or formatted as BibTeX entries for easy inclusion
   102→/// in scientific manuscripts.
   103→///
   104→/// # Arguments
   105→/// * `template` - Template identifier (e.g., "MNI152Lin", "MNI152NLin2009cAsym")
   106→/// * `bibtex` - If true, format citations as BibTeX entries; if false, return raw references
   107→///
   108→/// # Returns
   109→/// * `Result<Vec<String>>` - List of citations formatted according to the `bibtex` parameter
   110→///
   111→/// # Errors
   112→/// Returns `TemplateFlowError::TemplateNotFound` if the template doesn't exist.
   113→///
   114→/// # Example
   115→/// ```no_run
   116→/// use templateflow::api::get_citations;
   117→/// 
   118→/// // Get raw citations
   119→/// let citations = get_citations("MNI152Lin", false).unwrap();
   120→/// for citation in &citations {
   121→///     println!("Reference: {}", citation);
   122→/// }
   123→/// 
   124→/// // Get BibTeX-formatted citations
   125→/// let bibtex_citations = get_citations("MNI152Lin", true).unwrap();
   126→/// for entry in &bibtex_citations {
   127→///     println!("{}", entry);
   128→/// }
   129→/// ```
   130→pub fn get_citations(template: &str, bibtex: bool) -> Result<Vec<String>> {
   131→    let metadata = get_metadata(template)?;
   132→    
   133→    let citations: Vec<String> = if bibtex {
   134→        // TODO: Implement BibTeX formatting
   135→        metadata.references_and_links
   136→            .iter()
   137→            .enumerate()
   138→            .map(|(idx, ref_val)| {
   139→                format!(
   140→                    "@misc{{{}{},\n  title = {{{}}},\n  note = {{{}}}\n}}",
   141→                    template,
   142→                    idx + 1,
   143→                    metadata.name,
   144→                    serde_json::to_string(ref_val).unwrap_or_default()
   145→                )
   146→            })
   147→            .collect()
   148→    } else {
   149→        metadata.references_and_links
   150→            .iter()
   151→            .map(|v| serde_json::to_string_pretty(v).unwrap_or_default())
   152→            .collect()
   153→    };
   154→    
   155→    Ok(citations)
   156→}
   157→
   158→/// List available templates
   159→///
   160→/// Returns a list of all available brain templates in the TemplateFlow repository.
   161→/// Can optionally filter templates based on BIDS entities (e.g., templates that
   162→/// have files with specific resolution or suffix).
   163→///
   164→/// # Arguments
   165→/// * `query` - Optional query parameters as key-value pairs to filter templates.
   166→///   Common query keys include:
   167→///   - `"res"` or `"resolution"`: Spatial resolution (e.g., "01", "02")
   168→///   - `"suffix"`: File type suffix (e.g., "T1w", "mask", "brain")
   169→///   - `"atlas"`: Atlas name (e.g., "AAL", "Schaefer2018")
   170→///   - `"desc"` or `"description"`: Description label
   171→///
   172→/// # Returns
   173→/// * `Result<Vec<String>>` - Sorted list of template identifiers
   174→///
   175→/// # Example
   176→/// ```no_run
   177→/// use templateflow::api::templates;
   178→/// use std::collections::HashMap;
   179→/// 
   180→/// // Get all available templates
   181→/// let all_templates = templates(None).unwrap();
   182→/// println!("Found {} templates", all_templates.len());
   183→/// 
   184→/// // Get templates that have 1mm resolution files
   185→/// let mut query = HashMap::new();
   186→/// query.insert("res".to_string(), "01".to_string());
   187→/// let high_res_templates = templates(Some(&query)).unwrap();
   188→/// 
   189→/// // Get templates with T1-weighted images
   190→/// let mut query = HashMap::new();
   191→/// query.insert("suffix".to_string(), "T1w".to_string());
   192→/// let t1w_templates = templates(Some(&query)).unwrap();
   193→/// ```
   194→pub fn templates(query: Option<&HashMap<String, String>>) -> Result<Vec<String>> {
   195→    ensure_layout()?;
   196→    
   197→    let layout_guard = LAYOUT.lock().unwrap();
   198→    let layout = layout_guard.as_ref().unwrap();
   199→    
   200→    if let Some(query_params) = query {
   201→        // Get all files matching the query
   202→        let files = layout.query(query_params);
   203→        
   204→        // Extract unique template names
   205→        let mut template_set = std::collections::HashSet::new();
   206→        for file in files {
   207→            template_set.insert(file.template.clone());
   208→        }
   209→        
   210→        let mut templates: Vec<String> = template_set.into_iter().collect();
   211→        templates.sort();
   212→        Ok(templates)
   213→    } else {
   214→        // Return all templates
   215→        let mut templates: Vec<String> = layout.get_templates()
   216→            .into_iter()
   217→            .map(|s| s.to_string())
   218→            .collect();
   219→        templates.sort();
   220→        Ok(templates)
   221→    }
   222→}
   223→
   224→/// List files for a template with BIDS queries
   225→///
   226→/// Returns a list of file paths available for a specific template, optionally
   227→/// filtered by BIDS entities. This function does not download files, it only
   228→/// lists what's available in the repository.
   229→///
   230→/// # Arguments
   231→/// * `template` - Template identifier (e.g., "MNI152Lin", "MNI152NLin2009cAsym")
   232→/// * `query` - Optional query parameters as key-value pairs to filter files.
   233→///   Common query keys include:
   234→///   - `"res"` or `"resolution"`: Spatial resolution (e.g., "01", "02")
   235→///   - `"suffix"`: File type (e.g., "T1w", "mask", "brain", "probseg")
   236→///   - `"atlas"`: Atlas name (e.g., "AAL", "Schaefer2018")
   237→///   - `"hemi"` or `"hemisphere"`: Hemisphere ("L" or "R")
   238→///   - `"desc"` or `"description"`: Description label
   239→///   - `"ext"` or `"extension"`: File extension (e.g., ".nii.gz", ".gii")
   240→///
   241→/// # Returns
   242→/// * `Result<Vec<PathBuf>>` - List of relative file paths matching the query
   243→///
   244→/// # Errors
   245→/// Returns `TemplateFlowError::NoFilesMatched` if no files match the query.
   246→///
   247→/// # Example
   248→/// ```no_run
   249→/// use templateflow::api::ls;
   250→/// use std::collections::HashMap;
   251→/// 
   252→/// // List all files for a template
   253→/// let all_files = ls("MNI152Lin", None).unwrap();
   254→/// println!("Template has {} files", all_files.len());
   255→/// 
   256→/// // List only 1mm resolution T1-weighted images
   257→/// let mut query = HashMap::new();
   258→/// query.insert("res".to_string(), "01".to_string());
   259→/// query.insert("suffix".to_string(), "T1w".to_string());
   260→/// let t1w_files = ls("MNI152Lin", Some(&query)).unwrap();
   261→/// 
   262→/// // List brain masks at any resolution
   263→/// let mut query = HashMap::new();
   264→/// query.insert("suffix".to_string(), "mask".to_string());
   265→/// let mask_files = ls("MNI152Lin", Some(&query)).unwrap();
   266→/// ```
   267→pub fn ls(template: &str, query: Option<&HashMap<String, String>>) -> Result<Vec<PathBuf>> {
   268→    ensure_layout()?;
   269→    
   270→    let layout_guard = LAYOUT.lock().unwrap();
   271→    let layout = layout_guard.as_ref().unwrap();
   272→    
   273→    // Build query with template
   274→    let mut full_query = HashMap::new();
   275→    full_query.insert("tpl".to_string(), template.to_string());
   276→    
   277→    // Add additional query parameters if provided
   278→    if let Some(params) = query {
   279→        for (key, value) in params {
   280→            full_query.insert(key.clone(), value.clone());
   281→        }
   282→    }
   283→    
   284→    // Query the layout
   285→    let files = layout.query(&full_query);
   286→    
   287→    if files.is_empty() {
   288→        return Err(TemplateFlowError::NoFilesMatched);
   289→    }
   290→    
   291→    // Convert to paths
   292→    let paths: Vec<PathBuf> = files.into_iter()
   293→        .map(|f| f.path.clone())
   294→        .collect();
   295→    
   296→    Ok(paths)
   297→}
   298→
   299→/// Download and return file paths for a template
   300→///
   301→/// Downloads template files from S3 to the local cache and returns their paths.
   302→/// Files are cached locally, so subsequent calls will return immediately without
   303→/// re-downloading. The local cache is located at `~/.cache/templateflow` by default.
   304→///
   305→/// # Arguments
   306→/// * `template` - Template identifier (e.g., "MNI152Lin", "MNI152NLin2009cAsym")
   307→/// * `query` - Optional query parameters as key-value pairs to filter files.
   308→///   See [`ls`] for available query keys.
   309→///
   310→/// # Returns
   311→/// * `Result<Vec<PathBuf>>` - List of absolute paths to downloaded files in the local cache
   312→///
   313→/// # Errors
   314→/// - Returns `TemplateFlowError::NoFilesMatched` if no files match the query
   315→/// - Returns `TemplateFlowError::DownloadError` if network issues occur
   316→/// - Returns `TemplateFlowError::IoError` if file system operations fail
   317→///
   318→/// # Example
   319→/// ```no_run
   320→/// use templateflow::api::get;
   321→/// use std::collections::HashMap;
   322→/// 
   323→/// // Download all files for a template (may be many files!)
   324→/// let all_files = get("MNI152Lin", None).unwrap();
   325→/// println!("Downloaded {} files", all_files.len());
   326→/// 
   327→/// // Download only the 1mm T1-weighted image
   328→/// let mut query = HashMap::new();
   329→/// query.insert("res".to_string(), "01".to_string());
   330→/// query.insert("suffix".to_string(), "T1w".to_string());
   331→/// let t1w_files = get("MNI152Lin", Some(&query)).unwrap();
   332→/// 
   333→/// // Files are cached, so this returns immediately
   334→/// let cached_files = get("MNI152Lin", Some(&query)).unwrap();
   335→/// assert_eq!(t1w_files, cached_files);
   336→/// ```
   337→pub fn get(template: &str, query: Option<&HashMap<String, String>>) -> Result<Vec<PathBuf>> {
   338→    // First list the files
   339→    let files = ls(template, query)?;
   340→    
   341→    // Download each file
   342→    let mut downloaded_paths = Vec::new();
   343→    
   344→    for file_path in files {
   345→        // Construct local path
   346→        let local_path = CONFIG.home.join(&file_path);
   347→        
   348→        // Skip if already exists
   349→        if local_path.exists() {
   350→            downloaded_paths.push(local_path);
   351→            continue;
   352→        }
   353→        
   354→        // Download the file using the path relative to S3 root
   355→        s3::download_file_sync(&file_path.to_string_lossy(), &local_path, true)?;
   356→        downloaded_paths.push(local_path);
   357→    }
   358→    
   359→    Ok(downloaded_paths)
   360→}
   361→
   362→/// Asynchronously download and return file paths for a template
   363→///
   364→/// Async version of [`get`]. Downloads template files from S3 to the local cache
   365→/// asynchronously. Files are downloaded sequentially but without blocking the
   366→/// thread. For concurrent downloads of multiple files, use [`get_multiple_async`].
   367→///
   368→/// # Arguments
   369→/// * `template` - Template identifier (e.g., "MNI152Lin", "MNI152NLin2009cAsym")
   370→/// * `query` - Optional query parameters as key-value pairs to filter files.
   371→///   See [`ls`] for available query keys.
   372→///
   373→/// # Returns
   374→/// * `Result<Vec<PathBuf>>` - List of absolute paths to downloaded files in the local cache
   375→///
   376→/// # Errors
   377→/// - Returns `TemplateFlowError::NoFilesMatched` if no files match the query
   378→/// - Returns `TemplateFlowError::DownloadError` if network issues occur
   379→/// - Returns `TemplateFlowError::IoError` if file system operations fail
   380→///
   381→/// # Example
   382→/// ```no_run
   383→/// use templateflow::api::get_async;
   384→/// use std::collections::HashMap;
   385→/// 
   386→/// # async fn example() -> Result<(), Box<dyn std::error::Error>> {
   387→/// // Download all files for a template asynchronously
   388→/// let all_files = get_async("MNI152Lin", None).await?;
   389→/// println!("Downloaded {} files", all_files.len());
   390→/// 
   391→/// // Download specific files with query
   392→/// let mut query = HashMap::new();
   393→/// query.insert("res".to_string(), "01".to_string());
   394→/// query.insert("suffix".to_string(), "T1w".to_string());
   395→/// let t1w_files = get_async("MNI152Lin", Some(&query)).await?;
   396→/// 
   397→/// // Use in async context with other async operations
   398→/// let (template_files, other_data) = tokio::join!(
   399→///     get_async("MNI152Lin", Some(&query)),
   400→///     other_async_operation()
   401→/// );
   402→/// # Ok(())
   403→/// # }
   404→/// # async fn other_async_operation() -> Result<(), Box<dyn std::error::Error>> { Ok(()) }
   405→/// ```
   406→pub async fn get_async(template: &str, query: Option<&HashMap<String, String>>) -> Result<Vec<PathBuf>> {
   407→    // First list the files
   408→    let files = ls(template, query)?;
   409→    
   410→    // Download each file
   411→    let mut downloaded_paths = Vec::new();
   412→    
   413→    for file_path in files {
   414→        // Construct local path
   415→        let local_path = CONFIG.home.join(&file_path);
   416→        
   417→        // Skip if already exists
   418→        if local_path.exists() {
   419→            downloaded_paths.push(local_path);
   420→            continue;
   421→        }
   422→        
   423→        // Download the file using the path relative to S3 root
   424→        s3::download_file(&file_path.to_string_lossy(), &local_path, true).await?;
   425→        downloaded_paths.push(local_path);
   426→    }
   427→    
   428→    Ok(downloaded_paths)
   429→}
   430→
   431→/// Asynchronously download multiple files concurrently
   432→///
   433→/// Downloads multiple template files in parallel for improved performance when
   434→/// fetching many files. This function is particularly useful when downloading
   435→/// entire templates or large sets of files, as it can significantly reduce
   436→/// total download time compared to sequential downloads.
   437→///
   438→/// Files that are already cached are returned immediately without re-downloading.
   439→/// Only missing files are downloaded concurrently.
   440→///
   441→/// # Arguments
   442→/// * `template` - Template identifier (e.g., "MNI152Lin", "MNI152NLin2009cAsym")
   443→/// * `query` - Optional query parameters as key-value pairs to filter files.
   444→///   See [`ls`] for available query keys.
   445→///
   446→/// # Returns
   447→/// * `Result<Vec<PathBuf>>` - List of absolute paths to downloaded files in the local cache
   448→///
   449→/// # Errors
   450→/// - Returns `TemplateFlowError::NoFilesMatched` if no files match the query
   451→/// - Returns `TemplateFlowError::DownloadError` if any download fails
   452→/// - Returns `TemplateFlowError::IoError` if file system operations fail
   453→///
   454→/// # Example
   455→/// ```no_run
   456→/// use templateflow::api::get_multiple_async;
   457→/// use std::collections::HashMap;
   458→/// 
   459→/// # async fn example() -> Result<(), Box<dyn std::error::Error>> {
   460→/// // Download all atlas files concurrently
   461→/// let mut query = HashMap::new();
   462→/// query.insert("atlas".to_string(), "AAL".to_string());
   463→/// let atlas_files = get_multiple_async("MNI152NLin2009cAsym", Some(&query)).await?;
   464→/// println!("Downloaded {} atlas files in parallel", atlas_files.len());
   465→/// 
   466→/// // Download all files at a specific resolution
   467→/// let mut query = HashMap::new();
   468→/// query.insert("res".to_string(), "01".to_string());
   469→/// let high_res_files = get_multiple_async("MNI152Lin", Some(&query)).await?;
   470→/// 
   471→/// // Measure performance improvement
   472→/// use std::time::Instant;
   473→/// let start = Instant::now();
   474→/// let files = get_multiple_async("OASIS30ANTs", None).await?;
   475→/// println!("Downloaded {} files in {:?}", files.len(), start.elapsed());
   476→/// # Ok(())
   477→/// # }
   478→/// ```
   479→pub async fn get_multiple_async(template: &str, query: Option<&HashMap<String, String>>) -> Result<Vec<PathBuf>> {
   480→    use futures::future::join_all;
   481→    
   482→    // First list the files
   483→    let files = ls(template, query)?;
   484→    
   485→    // Prepare download tasks
   486→    let mut download_tasks = Vec::new();
   487→    let mut already_cached = Vec::new();
   488→    
   489→    for file_path in files {
   490→        // Construct local path
   491→        let local_path = CONFIG.home.join(&file_path);
   492→        
   493→        // Skip if already exists
   494→        if local_path.exists() {
   495→            already_cached.push(local_path);
   496→            continue;
   497→        }
   498→        
   499→        // Create download task
   500→        let s3_path = file_path.to_string_lossy().to_string();
   501→        let local_path_clone = local_path.clone();
   502→        let download_task = async move {
   503→            s3::download_file(&s3_path, &local_path_clone, true).await?;
   504→            Ok::<PathBuf, TemplateFlowError>(local_path_clone)
   505→        };
   506→        
   507→        download_tasks.push(download_task);
   508→    }
   509→    
   510→    // Execute all downloads concurrently
   511→    let download_results = join_all(download_tasks).await;
   512→    
   513→    // Collect results
   514→    let mut downloaded_paths = already_cached;
   515→    for result in download_results {
   516→        downloaded_paths.push(result?);
   517→    }
   518→    
   519→    Ok(downloaded_paths)
   520→}

