//! Example of parallel downloads with advanced options
//!
//! This example demonstrates how to use the advanced parallel download
//! functionality to efficiently download multiple template files with
//! configurable concurrency, retry logic, and progress tracking.

use std::collections::HashMap;
use std::time::Instant;
use templateflow::{get_multiple_async_advanced, ParallelDownloadOptions, ls, get_multiple_async};

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("TemplateFlow Parallel Download Example\n");

    // Example 1: Basic parallel download (all files downloaded concurrently)
    println!("Example 1: Basic parallel download");
    println!("---------------------------------");

    let mut query = HashMap::new();
    query.insert("res".to_string(), "01".to_string());
    query.insert("suffix".to_string(), "T1w".to_string());

    // First, let's see what files match our query
    let files_to_download = ls("MNI152Lin", Some(&query))?;
    println!("Found {} files matching query", files_to_download.len());

    // Download them with basic parallel functionality
    let start = Instant::now();
    let downloaded_files = get_multiple_async("MNI152Lin", Some(&query)).await?;
    let duration = start.elapsed();

    println!("Downloaded {} files in {:?}", downloaded_files.len(), duration);
    for file in &downloaded_files {
        println!("  - {}", file.display());
    }

    println!("\n");

    // Example 2: Advanced parallel download with custom options
    println!("Example 2: Advanced parallel download with custom options");
    println!("-------------------------------------------------------");

    // Download all brain masks with controlled concurrency
    let mut query = HashMap::new();
    query.insert("suffix".to_string(), "mask".to_string());

    let options = ParallelDownloadOptions {
        max_concurrent: 3,      // Limit to 3 concurrent downloads
        max_retries: 5,         // Retry failed downloads up to 5 times
        show_progress: true,    // Show progress bars
    };

    let files_to_download = ls("MNI152NLin2009cAsym", Some(&query))?;
    println!("Found {} mask files to download", files_to_download.len());

    let start = Instant::now();
    let downloaded_files = get_multiple_async_advanced(
        "MNI152NLin2009cAsym", 
        Some(&query), 
        options
    ).await?;
    let duration = start.elapsed();

    println!("\nDownloaded {} files in {:?}", downloaded_files.len(), duration);

    println!("\n");

    // Example 3: Download entire template with progress
    println!("Example 3: Download entire template");
    println!("---------------------------------");

    // Check how many files the template has
    let all_files = ls("Fischer344", None)?;
    println!("Template 'Fischer344' has {} total files", all_files.len());

    // Download all files with optimized settings
    let options = ParallelDownloadOptions {
        max_concurrent: 10,     // Higher concurrency for many small files
        max_retries: 3,
        show_progress: true,
    };

    println!("Downloading all files...");
    let start = Instant::now();
    let downloaded_files = get_multiple_async_advanced(
        "Fischer344", 
        None,  // No query filter - download everything
        options
    ).await?;
    let duration = start.elapsed();

    println!("\nSuccessfully downloaded {} files in {:?}", downloaded_files.len(), duration);

    // Calculate download speed
    let total_size: u64 = downloaded_files.iter()
        .filter_map(|path| std::fs::metadata(path).ok())
        .map(|meta| meta.len())
        .sum();

    let mb_downloaded = total_size as f64 / (1024.0 * 1024.0);
    let seconds = duration.as_secs_f64();
    let speed = mb_downloaded / seconds;

    println!("Total size: {:.2} MB", mb_downloaded);
    println!("Average speed: {:.2} MB/s", speed);

    println!("\n");

    // Example 4: Comparing sequential vs parallel performance
    println!("Example 4: Performance comparison");
    println!("--------------------------------");

    let mut query = HashMap::new();
    query.insert("atlas".to_string(), "Schaefer2018".to_string());
    query.insert("res".to_string(), "01".to_string());

    let files_to_download = ls("MNI152NLin2009cAsym", Some(&query))?;
    println!("Comparing download of {} atlas files", files_to_download.len());

    // Clear cache first to ensure fair comparison
    // (In a real scenario, you might want to keep the cache)

    // Parallel download with default settings
    println!("\nParallel download (5 concurrent):");
    let start = Instant::now();
    let _ = get_multiple_async("MNI152NLin2009cAsym", Some(&query)).await?;
    let parallel_time = start.elapsed();
    println!("  Time: {:?}", parallel_time);

    // You could also test with different concurrency levels
    let options = ParallelDownloadOptions {
        max_concurrent: 1,  // Sequential
        max_retries: 3,
        show_progress: false,
    };

    println!("\nSequential download (1 concurrent):");
    let start = Instant::now();
    let _ = get_multiple_async_advanced(
        "MNI152NLin2009cAsym", 
        Some(&query), 
        options
    ).await?;
    let sequential_time = start.elapsed();
    println!("  Time: {:?}", sequential_time);

    let speedup = sequential_time.as_secs_f64() / parallel_time.as_secs_f64();
    println!("\nSpeedup: {:.2}x faster with parallel downloads", speedup);

    Ok(())
}

