//! Tests for parallel download functionality

use std::collections::HashMap;
use std::time::Instant;
use templateflow::{
    get_multiple_async, get_multiple_async_advanced, ls, ParallelDownloadOptions,
};

#[tokio::test]
#[ignore] // Requires network access
async fn test_basic_parallel_download() {
    // Download multiple small files
    let mut query = HashMap::new();
    query.insert("suffix".to_string(), "json".to_string());

    let files = ls("MNI152Lin", Some(&query)).unwrap();
    assert!(!files.is_empty(), "Should find JSON files");

    let start = Instant::now();
    let downloaded = get_multiple_async("MNI152Lin", Some(&query)).await.unwrap();
    let duration = start.elapsed();

    assert_eq!(downloaded.len(), files.len(), "Should download all files");
    println!("Downloaded {} files in {:?}", downloaded.len(), duration);

    // Verify all files exist
    for path in &downloaded {
        assert!(path.exists(), "Downloaded file should exist: {:?}", path);
    }
}

#[tokio::test]
#[ignore] // Requires network access
async fn test_advanced_parallel_download_with_options() {
    // Test with custom options
    let mut query = HashMap::new();
    query.insert("suffix".to_string(), "json".to_string());

    let options = ParallelDownloadOptions {
        max_concurrent: 2,
        max_retries: 5,
        show_progress: false, // Disable for tests
    };

    let downloaded = get_multiple_async_advanced("MNI152Lin", Some(&query), options)
        .await
        .unwrap();

    assert!(!downloaded.is_empty(), "Should download files");

    // Verify all files exist
    for path in &downloaded {
        assert!(path.exists(), "Downloaded file should exist: {:?}", path);
    }
}

#[tokio::test]
#[ignore] // Requires network access
async fn test_parallel_download_with_cached_files() {
    // First download some files
    let mut query = HashMap::new();
    query.insert("suffix".to_string(), "json".to_string());

    let first_download = get_multiple_async("MNI152Lin", Some(&query)).await.unwrap();
    assert!(!first_download.is_empty());

    // Download again - should use cache
    let start = Instant::now();
    let second_download = get_multiple_async("MNI152Lin", Some(&query)).await.unwrap();
    let cached_duration = start.elapsed();

    assert_eq!(first_download.len(), second_download.len());
    assert_eq!(first_download, second_download);

    // Cached download should be very fast
    println!("Cached download took: {:?}", cached_duration);
    assert!(cached_duration.as_millis() < 100, "Cached files should return quickly");
}

#[tokio::test]
#[ignore] // Requires network access
async fn test_parallel_download_concurrency_limit() {
    // Test that concurrency limit is respected
    let mut query = HashMap::new();
    query.insert("res".to_string(), "01".to_string());

    let options = ParallelDownloadOptions {
        max_concurrent: 1, // Sequential
        max_retries: 1,
        show_progress: false,
    };

    let start = Instant::now();
    let sequential = get_multiple_async_advanced("Fischer344", Some(&query), options.clone())
        .await
        .unwrap();
    let sequential_time = start.elapsed();

    // Now with higher concurrency
    let options_parallel = ParallelDownloadOptions {
        max_concurrent: 5,
        max_retries: 1,
        show_progress: false,
    };

    let start = Instant::now();
    let parallel = get_multiple_async_advanced("Fischer344", Some(&query), options_parallel)
        .await
        .unwrap();
    let parallel_time = start.elapsed();

    assert_eq!(sequential.len(), parallel.len());

    println!("Sequential time: {:?}", sequential_time);
    println!("Parallel time: {:?}", parallel_time);

    // Parallel should generally be faster (though not guaranteed due to network variability)
    // We just verify both completed successfully
}

#[tokio::test]
async fn test_parallel_download_empty_query() {
    // Test with query that returns no files
    let mut query = HashMap::new();
    query.insert("suffix".to_string(), "nonexistent".to_string());

    let result = get_multiple_async("MNI152Lin", Some(&query)).await;
    assert!(result.is_err(), "Should error when no files match");
}

#[tokio::test]
async fn test_parallel_download_options_default() {
    let options = ParallelDownloadOptions::default();
    assert_eq!(options.max_concurrent, 5);
    assert_eq!(options.max_retries, 3);
    assert_eq!(options.show_progress, true);
}

#[test]
fn test_parallel_download_options_clone() {
    let options = ParallelDownloadOptions {
        max_concurrent: 10,
        max_retries: 2,
        show_progress: false,
    };

    let cloned = options.clone();
    assert_eq!(options.max_concurrent, cloned.max_concurrent);
    assert_eq!(options.max_retries, cloned.max_retries);
    assert_eq!(options.show_progress, cloned.show_progress);
}

